-- 1. Tenterden × Web Design
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'web-design',
  'tenterden',
  'Tenterden is known as the Jewel of the Weald, and for good reason. Its broad, tree-lined High Street is widely regarded as one of the finest in Kent, home to independent boutiques, galleries, tea rooms, and professional services that attract visitors from across the South East. With a population of around 8,000 but a rural catchment extending deep into the Weald, Tenterden businesses serve a far larger audience than the town''s size suggests. Visitors drawn by the Kent and East Sussex Railway, the nearby Chapel Down Winery, and the town''s quintessential English character browse local shops and search for local services online before and after their visit. We build bespoke websites for Tenterden businesses that capture the town''s distinctive character, convert tourist browsers and local residents alike, and present your business with the quality this remarkable High Street deserves.',
  'Tenterden sits at the heart of the Weald, a small market town with outsized commercial influence. The High Street stretches from St Mildred''s Church to the Town Hall, lined with independent businesses that give the town its boutique character. The Kent and East Sussex Railway heritage steam line draws thousands of visitors annually, while Chapel Down Winery and Tenterden Vineyard attract food and wine enthusiasts from London and beyond. The town falls within Ashford Borough but operates with a distinctly independent identity. The affluent rural catchment includes surrounding villages and hamlets where residents rely on Tenterden as their commercial centre.',
  'The web design landscape for Tenterden businesses reflects the town''s small scale. Many independent shops and services run dated websites or rely solely on social media. A handful of more established firms have invested in professional sites, but the overall standard is inconsistent. This creates a clear opportunity: a business with a well-designed, modern website stands out dramatically in the Tenterden market. The tourism dimension adds another layer, as visitors searching for Tenterden experiences expect polished, visually appealing websites.',
  'Our approach for Tenterden businesses balances aesthetic quality with commercial effectiveness. A town this visually distinctive demands websites that reflect its character, but beauty without conversion architecture is a missed opportunity. We build sites that capture Tenterden''s charm through authentic photography and thoughtful design while engineering every page to guide visitors toward booking, buying, or enquiring. Tourist traffic gets converted alongside local loyal customers.',
  '{"population": 8000, "catchment": "Extensive rural Wealden catchment", "borough": "Ashford", "business_districts": ["High Street", "Station Road area"], "key_fact": "Known as the Jewel of the Weald with one of the finest High Streets in Kent"}',
  '[{"title": "Dated websites failing to match Tenterden''s High Street quality", "description": "Visitors come to Tenterden expecting a premium experience. They walk the beautiful High Street, admire the independent shops, and search for businesses online. A dated, clunky website destroys the impression the town itself has carefully cultivated. Your digital presence must match the character of Tenterden''s physical environment."}, {"title": "Tourist traffic unconverted without proper web presence", "description": "Thousands of visitors arrive in Tenterden via the Kent and East Sussex Railway and Chapel Down Winery each year. Many search for local businesses before or during their visit. Without a website optimised for this tourist traffic, Tenterden businesses miss enquiries and sales from an audience already predisposed to spend."}, {"title": "Social media replacing websites at the cost of credibility", "description": "Some Tenterden businesses rely entirely on Facebook or Instagram as their web presence. While social media has its place, customers searching Google for your services find nothing. Potential clients who want to verify your credibility before visiting the High Street find no website at all, and move on to a competitor."}]',
  '[{"title": "Websites reflecting Tenterden''s distinctive character", "description": "We design websites that capture the quality and charm of the Jewel of the Weald. Authentic photography, thoughtful typography, and design that feels appropriate for a business on one of Kent''s finest High Streets. Your website becomes a natural digital extension of the Tenterden experience."}, {"title": "Tourist conversion alongside local customer journeys", "description": "Every Tenterden site we build serves two audiences: loyal local customers and the visitors drawn by the heritage railway, Chapel Down, and the High Street itself. Dual conversion paths ensure both audiences find what they need and are guided toward booking, buying, or making contact."}, {"title": "Mobile-optimised design for visiting browsers", "description": "Tourists browsing on mobile while walking the High Street or waiting at the Kent and East Sussex Railway station need a website that loads instantly and works flawlessly on their phone. Every Tenterden site we build is mobile-first, ensuring visitors can find, engage, and convert on any device."}]',
  '[{"question": "How long does a Tenterden website project take?", "answer": "Most Tenterden projects launch within four to six weeks. We begin with understanding your position on the High Street and in the wider Wealden market, then move through design, development, and testing. Businesses with seasonal peaks can plan launch timing to maximise impact during key visitor periods."}, {"question": "Will my site rank for Tenterden searches?", "answer": "Every site includes foundational SEO with Tenterden-specific titles, descriptions, and content. The relatively low online competition in Tenterden means well-optimised sites can achieve strong rankings faster than in larger Kent towns. We typically see movement within four to eight weeks for targeted local terms."}, {"question": "Can you photograph my Tenterden business for the website?", "answer": "We strongly recommend professional photography for Tenterden businesses because the town''s visual character is such a powerful asset. We coordinate photography sessions that capture your business within the context of the High Street and surrounding Wealden landscape, creating imagery that resonates with both locals and visitors."}, {"question": "Do you work with tourism-related Tenterden businesses?", "answer": "Yes. We work with accommodation providers, restaurants, shops, and experience businesses across the Tenterden area. Tourism websites require specific functionality including booking integration, seasonal content, and design that appeals to the visitor demographic. We build all of this as standard for Tenterden tourism clients."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
