-- 6. Tenterden × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'tenterden',
  'Tenterden is one of the most photogenic towns in Kent, yet many of its businesses fail to capitalise on this visual advantage through social media. The broad, tree-lined High Street, the steam trains of the Kent and East Sussex Railway, the vineyards and Wealden landscape, all provide extraordinary content opportunities that most Tenterden businesses underuse. Instagram, in particular, is a natural fit for the town''s boutique, hospitality, and artisan businesses, where beautiful imagery drives discovery and desire. Facebook connects the local community and surrounding villages where residents share recommendations. We set up and optimise social media profiles for Tenterden businesses, creating professional presences that showcase the town''s visual appeal, engage both locals and visitors, and convert social media browsers into customers walking through your High Street door.',
  'Tenterden''s social media landscape benefits from the town''s extraordinary visual appeal. The High Street, St Mildred''s Church, the heritage railway, and the surrounding Wealden countryside provide a continuous stream of photogenic content hooks. The town attracts a visitor demographic that actively discovers destinations through Instagram. Local residents use Facebook groups for recommendations and community engagement. The food and wine connection through Chapel Down Winery and Tenterden Vineyard creates crossover content opportunities with established audiences of food and drink enthusiasts.',
  'Social media quality among Tenterden businesses is mixed. A handful of boutiques and food businesses have built strong Instagram followings that drive real commercial results. Many others post inconsistently or have outdated profiles that fail to represent their business attractively. The opportunity is significant: Tenterden''s visual appeal means good social media content almost creates itself, but most businesses are not capturing or presenting it effectively.',
  'Our social media setup for Tenterden leverages the town''s natural visual advantage. Instagram profiles built around the beautiful High Street context and Wealden surroundings. Facebook presences optimised for community engagement and visitor information. Content frameworks using the heritage railway, seasonal vineyard events, and market town calendar as ongoing content hooks. We set up profiles that showcase Tenterden''s charm and position your business at the heart of it.',
  '{"population": 8000, "catchment": "Extensive rural Wealden catchment", "borough": "Ashford", "business_districts": ["High Street", "Station Road area"], "key_fact": "Exceptionally photogenic town creating natural social media content advantages"}',
  '[{"title": "Tenterden''s visual appeal wasted on poor social media", "description": "The Jewel of the Weald provides one of the most photogenic commercial backdrops in Kent. Yet many Tenterden businesses post blurry phone photos or nothing at all. The visual advantage the town provides is being squandered by businesses that have not invested in presenting their social media professionally."}, {"title": "Visitor discovery channel untapped by Tenterden businesses", "description": "Tourists planning Tenterden visits actively browse Instagram and Facebook for inspiration. A beautifully presented social media profile drives discovery, desire, and direct bookings. Without optimised social presences, Tenterden businesses are invisible in the channel where visitors increasingly plan their trips."}, {"title": "Inconsistent profiles undermining Tenterden High Street credibility", "description": "A potential visitor checks your Instagram before deciding to visit your shop. They find the last post was three months ago, the profile picture is blurry, and the bio contains outdated opening hours. They move on to the competitor next door whose profile is polished and active."}]',
  '[{"title": "Instagram setup showcasing Tenterden''s visual character", "description": "We build Instagram profiles that leverage Tenterden''s extraordinary visual appeal. Professional photography of your business within the High Street context, curated grid layouts, and optimised bios that drive discovery. Your Instagram becomes a destination in itself, drawing visitors to your door."}, {"title": "Facebook community presence for local and visitor engagement", "description": "Professional Facebook setup optimised for both the local Tenterden community and visiting audience. Complete business information, engaging cover imagery, and integration with relevant community groups. Your business becomes part of the recommendation conversations that drive commerce in the town."}, {"title": "Seasonal content framework using Tenterden''s calendar", "description": "The Kent and East Sussex Railway events, Chapel Down harvest seasons, Tenterden market days, and Wealden seasonal changes provide a natural content calendar. We build a framework that maps content to these local hooks, ensuring your social media stays relevant and authentically Tenterden throughout the year."}]',
  '[{"question": "Which social platforms matter most for Tenterden businesses?", "answer": "Instagram is essential for retail, hospitality, and artisan businesses due to Tenterden''s visual appeal and the visitor discovery dynamic. Facebook remains important for local community engagement and surrounding village residents. We recommend the right platform mix based on your specific business type and audience."}, {"question": "Can you provide photography for our Tenterden social media?", "answer": "We strongly recommend professional photography that captures your business within the Tenterden context. We coordinate photography sessions on the High Street and in the Wealden surroundings, creating a library of images that populate your profiles and provide months of quality content."}, {"question": "How do you handle the seasonal nature of Tenterden''s visitor economy?", "answer": "We build content frameworks with seasonal variation reflecting Tenterden''s visitor calendar. Spring heritage railway events, summer High Street festivals, autumn vineyard harvest, winter festive shopping. Your social media peaks when visitor attention peaks, maximising commercial impact."}, {"question": "How long does social media setup take?", "answer": "A complete multi-platform setup typically takes one to two weeks. This includes platform strategy, professional visual asset creation, profile optimisation, and development of a seasonal content framework. Photography sessions, if included, may extend the timeline slightly depending on scheduling."}]',
  'trust'
)
