-- 7. Tenterden × Digital Marketing
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'digital-marketing',
  'tenterden',
  'Tenterden''s small population means traditional advertising reaches a limited audience quickly. Flyers, local press, and physical signage have a ceiling determined by the town''s 8,000 residents and passing footfall. Digital marketing breaks through that ceiling, reaching the affluent rural catchment across the Weald, the tourist audience planning visits around the Kent and East Sussex Railway and Chapel Down Winery, and the broader South East audience who may discover Tenterden as a destination. For a town that depends on drawing customers from beyond its boundaries, digital marketing is not optional, it is the mechanism that expands your addressable market from thousands to hundreds of thousands. We build targeted digital campaigns that bring the right visitors to Tenterden businesses, both online and through the High Street door.',
  'Tenterden''s digital marketing opportunity extends well beyond the town itself. The visitor economy draws from London, the wider South East, and increasingly from international tourists attracted to the Kent wine trail. The rural Wealden catchment extends across a wide geographic area where residents cannot be reached by physical advertising. Google and social media channels provide the ability to target these dispersed audiences with precision. The High Street''s strong independent retail character, the heritage railway, and the vineyard connections provide distinctive marketing angles that resonate with the affluent, experience-seeking audience Tenterden naturally attracts.',
  'Digital marketing among Tenterden businesses is underdeveloped. Most businesses rely on organic social media posting, if anything. Paid advertising on Google or social platforms is rare. This means advertising costs are low, competition for attention is minimal, and the early movers will establish presence in digital channels before competitors respond. For tourism-facing businesses, this opportunity is particularly significant.',
  'We approach Tenterden digital marketing with geographic and audience precision. Tourist campaigns target audiences in London and the South East with interests in food, wine, heritage, and countryside experiences. Local campaigns target the rural Wealden catchment with specific service messaging. Seasonal campaigns align with the Kent and East Sussex Railway calendar and vineyard events. Every pound reaches people likely to visit or buy.',
  '{"population": 8000, "catchment": "Extensive rural Wealden catchment", "borough": "Ashford", "business_districts": ["High Street", "Station Road area"], "key_fact": "Digital marketing expands addressable audience from 8,000 residents to hundreds of thousands of potential visitors"}',
  '[{"title": "Limited local audience capping Tenterden business growth", "description": "With 8,000 residents, Tenterden businesses quickly exhaust the local audience through traditional marketing. Without digital channels reaching the wider Wealden catchment and visitor audience, growth is capped by geography. Digital marketing breaks this ceiling by placing your business in front of audiences who have never heard of Tenterden."}, {"title": "Visitor economy under-marketed despite Tenterden''s appeal", "description": "Tenterden has the heritage railway, Chapel Down, a beautiful High Street, and vineyard tourism. Yet few businesses actively market to the visitor audience digitally. Aggregator sites and tourism boards capture this traffic instead. Direct digital marketing puts your Tenterden business in front of visitors before they arrive."}, {"title": "No measurable marketing for Tenterden independent businesses", "description": "A sponsored post on Facebook, a listing in a local magazine, a flyer drop. Tenterden businesses spend on marketing with no way to measure what works. Without tracking and attribution, budget allocation is guesswork and waste is invisible."}]',
  '[{"title": "Visitor attraction campaigns for Tenterden tourism businesses", "description": "We build digital campaigns targeting the specific demographics that visit Tenterden: London-based food and wine enthusiasts, heritage railway fans, countryside experience seekers. Precise audience targeting puts your business in front of people planning trips to the area, driving bookings before they arrive."}, {"title": "Rural catchment targeting for Tenterden service businesses", "description": "Google Ads and social campaigns targeting the specific postcodes and villages across the Weald where your potential customers live. Residents in surrounding areas who would naturally use Tenterden as their service hub discover your business through precisely targeted digital advertising."}, {"title": "Seasonal campaign management aligned with Tenterden''s calendar", "description": "Marketing intensity peaks when visitor opportunity peaks. Heritage railway special events, Chapel Down harvest season, summer High Street shopping, Christmas in Tenterden. We manage campaign budgets and messaging to align with the natural commercial rhythm of the town."}]',
  '[{"question": "What budget does a Tenterden business need for digital marketing?", "answer": "Effective campaigns can start from as little as three hundred to five hundred pounds per month in ad spend for local service businesses. Tourism-facing businesses may benefit from larger seasonal budgets aligned with visitor peaks. The low competition in Tenterden digital channels means modest budgets deliver strong returns."}, {"question": "Can digital marketing really reach visitors before they come to Tenterden?", "answer": "Absolutely. We target audiences in London and the South East with specific interests in food, wine, heritage, and countryside experiences. These people are actively planning day trips and weekends away. Your Tenterden business appears in their planning research, influencing their itinerary before they arrive."}, {"question": "How do you measure digital marketing results for a small Tenterden business?", "answer": "We track enquiries, bookings, and website visits attributed to each campaign. Monthly reports show exactly what your spend produced in measurable business outcomes. For retail businesses, we can also track direction requests and phone calls generated through Google Ads."}, {"question": "Should I invest in digital marketing year-round or just seasonally?", "answer": "It depends on your business. Tourism-facing businesses benefit from seasonal campaigns aligned with visitor peaks. Year-round service businesses benefit from consistent presence. We can design a hybrid approach that maintains baseline visibility while scaling up during peak Tenterden trading periods."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
